import { useState, useEffect } from "react";
import { ethers } from "ethers";
import {
  ROUTER_ADDRESS, ERC20_ABI, fmtN, shortAddr, swapDeadline,
} from "../../config/constants";
import TIcon from "../common/TIcon";
import Toast, { useToast } from "../common/Toast";

export default function AddLiqModal({ pair, signer, wallet, provider, onClose }) {
  const [amt0, setAmt0] = useState("");
  const [amt1, setAmt1] = useState("");
  const [reserves, setReserves] = useState({ r0: 0, r1: 0 });
  const [needApp0, setNeedApp0] = useState(false);
  const [needApp1, setNeedApp1] = useState(false);
  const [approv0, setApprov0] = useState(false);
  const [approv1, setApprov1] = useState(false);
  const [adding, setAdding] = useState(false);
  const [progress, setProgress] = useState(0);
  const [errMsg, setErrMsg] = useState("");
  const [bals, setBals] = useState({});
  const { toast, showToast } = useToast();

  const tA = pair.a;
  const tB = pair.b;
  const hasETH = tA.address === "native" || tB.address === "native";
  const erc20Tok = hasETH ? (tA.address === "native" ? tB : tA) : null;

  useEffect(() => {
    fetchBals();
    fetchReserves();
  }, [wallet, provider, pair]);

  useEffect(() => { checkAllowances(); }, [amt0, amt1, wallet, provider]);

  async function fetchReserves() {
    if (!pair.address || !provider) return;
    try {
      const PAIR_ABI = ["function getReserves() external view returns (uint112, uint112, uint32)"];
      const pairContract = new ethers.Contract(pair.address, PAIR_ABI, provider);
      const [r0, r1] = await pairContract.getReserves();
      setReserves({
        r0: parseFloat(ethers.formatUnits(r0, tA.decimals)),
        r1: parseFloat(ethers.formatUnits(r1, tB.decimals))
      });
    } catch {}
  }

  async function fetchBals() {
    const b = {};
    for (const t of [tA, tB]) {
      try {
        if (t.address === "native") b[t.symbol] = ethers.formatEther(await provider.getBalance(wallet));
        else {
          const c = new ethers.Contract(t.address, ERC20_ABI, provider);
          b[t.symbol] = ethers.formatUnits(await c.balanceOf(wallet), t.decimals);
        }
      } catch { b[t.symbol] = "0"; }
    }
    setBals(b);
  }

  const handleAmt0Change = (val) => {
    setAmt0(val);
    if (reserves.r0 > 0 && reserves.r1 > 0 && parseFloat(val) > 0) {
      setAmt1((parseFloat(val) * (reserves.r1 / reserves.r0)).toFixed(6));
    } else setAmt1("");
  };

  const handleAmt1Change = (val) => {
    setAmt1(val);
    if (reserves.r0 > 0 && reserves.r1 > 0 && parseFloat(val) > 0) {
      setAmt0((parseFloat(val) * (reserves.r0 / reserves.r1)).toFixed(6));
    } else setAmt0("");
  };

  async function checkAllowances() {
    if (!wallet || !provider) return;
    try {
      const check = async (tok, amt) => {
        if (tok.address === "native" || !amt || parseFloat(amt) <= 0) return false;
        const c = new ethers.Contract(tok.address, ERC20_ABI, provider);
        const al = await c.allowance(wallet, ROUTER_ADDRESS);
        return al < ethers.parseUnits(amt, tok.decimals);
      };
      setNeedApp0(await check(tA, amt0));
      setNeedApp1(await check(tB, amt1));
    } catch {}
  }

  async function approve(token, setAppr) {
    setAppr(true);
    try {
      const c = new ethers.Contract(token.address, ERC20_ABI, signer);
      const tx = await c.approve(ROUTER_ADDRESS, ethers.MaxUint256);
      await tx.wait();
      await checkAllowances();
      showToast(`✓ ${token.symbol} APPROVED`);
    } catch (e) { showToast("✕ APPROVE FAILED", "err"); }
    setAppr(false);
  }

  async function doAdd() {
    setAdding(true);
    const iv = setInterval(() => setProgress(p => Math.min(p + 8, 90)), 300);
    try {
      const ROUTER_LIQ_ABI = ["function addLiquidity(address,address,uint,uint,uint,uint,address,uint) external returns(uint,uint,uint)", "function addLiquidityETH(address,uint,uint,uint,address,uint) external payable returns(uint,uint,uint)"];
      const router = new ethers.Contract(ROUTER_ADDRESS, ROUTER_LIQ_ABI, signer);
      let tx;
      if (hasETH) {
        const ethAmt = tA.address === "native" ? amt0 : amt1;
        const tokAmt = tA.address === "native" ? amt1 : amt0;
        tx = await router.addLiquidityETH(erc20Tok.address, ethers.parseUnits(tokAmt, erc20Tok.decimals), 0, 0, wallet, swapDeadline(), { value: ethers.parseEther(ethAmt) });
      } else {
        tx = await router.addLiquidity(tA.address, tB.address, ethers.parseUnits(amt0, tA.decimals), ethers.parseUnits(amt1, tB.decimals), 0, 0, wallet, swapDeadline());
      }
      await tx.wait();
      clearInterval(iv); setProgress(100);
      setTimeout(() => { setAdding(false); setAmt0(""); setAmt1(""); fetchBals(); }, 1000);
    } catch (e) { clearInterval(iv); setAdding(false); showToast("✕ TX FAILED", "err"); }
  }

  const busy = adding || approv0 || approv1;
  const noAmt = !amt0 || !amt1 || parseFloat(amt0) <= 0 || parseFloat(amt1) <= 0;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <Toast toast={toast} />
        <div className="modal-hd">
          <div className="card-title">ADD_LIQUIDITY</div>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>

        {/* Input A */}
        <div className="token-box">
          <input type="number" placeholder="0.00" value={amt0} onChange={e => handleAmt0Change(e.target.value)} />
          <span className="usd-val">BAL: {fmtN(bals[tA.symbol] || "0", 4)}</span>
        </div>

        <div className="liq-plus">+</div>

        {/* Input B */}
        <div className="token-box">
          <input type="number" placeholder="0.00" value={amt1} onChange={e => handleAmt1Change(e.target.value)} />
          <span className="usd-val">BAL: {fmtN(bals[tB.symbol] || "0", 4)}</span>
        </div>

        <button 
            className="cyber-btn" 
            onClick={needApp0 ? () => approve(tA, setApprov0) : needApp1 ? () => approve(tB, setApprov1) : doAdd}
            disabled={busy || noAmt}
        >
            {needApp0 ? `APPROVE ${tA.symbol}` : needApp1 ? `APPROVE ${tB.symbol}` : adding ? "ADDING..." : "ADD LIQUIDITY"}
        </button>
      </div>
    </div>
  );
}
